using loka::core::State;
using loka::core::String;

inline loka::app::F BmiCalculator(
    State<String> *heightInput,
    State<String> *weightInput,
    State<String> *bmiResult)
{
  using namespace loka::app;
  return F()                       //
         << Text("BMI Calculator") //
         << Text("Height (cm)")    //
         << EditText(heightInput)  //
         << Text("Weight (kg)")    //
         << EditText(weightInput)  //
         << Text(bmiResult);
}
